sql:
SELECT association_id, dot_product AS maximum_dot_product
FROM gene_disease_associations
WHERE dot_product = (SELECT MAX(dot_product) FROM gene_disease_associations);

SELECT module, COUNT(DISTINCT user_id) AS users_count_per_module
FROM user_permissions
GROUP BY module;

SELECT source, status, COUNT(*) AS count
FROM gene_updates
GROUP BY source, status;

